+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownLink = {
+  end: number,
+  image: boolean,
+  label: string,
+  target: string,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
+      text = convertWikiLinks(text, options);
+    }
+    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
+      text = convertMarkdownLinks(text, options);
+    }
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to markdown',
+        before: '[[page#heading]] [[page|Display]] ![[image.png|300x200]]',
+        after: '[page > heading](page#heading) [Display](page) ![image.png](image.png)',
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert markdown links and images to wiki syntax',
+        before: '[page > heading](page#heading) ![alt](image.png)',
+        after: '[[page#heading]] ![[image.png|alt]]',
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    const records = [
+      {value: 'no-change' as const, description: 'Leaves this syntax unchanged.'},
+      {value: 'markdown' as const, description: 'Converts wiki syntax to markdown.'},
+      {value: 'wiki' as const, description: 'Converts markdown syntax to wiki syntax.'},
+    ];
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records,
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records,
+      }),
+    ];
+  }
+}
+
+function convertWikiLinks(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!?)\\[\\[([^\\]\\r\
]+)\\]\\]/g, (match, bang: string, contents: string) => {
+    const image = bang === '!';
+    if ((image ? options.imageStyle : options.linkStyle) !== 'markdown') {
+      return match;
+    }
+
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.substring(0, separator);
+    const suppliedDisplay = separator === -1 ? undefined : contents.substring(separator + 1);
+    const display = suppliedDisplay === undefined || (image && isEmbedSize(suppliedDisplay)) ? target : suppliedDisplay;
+    const defaultDisplay = defaultHeadingDisplay(target);
+    return image ? `![${display}](${target})` : `[${suppliedDisplay === undefined ? defaultDisplay : display}](${target})`;
+  });
+}
+
+function convertMarkdownLinks(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let cursor = 0;
+
+  while (cursor < text.length) {
+    const parsed = parseMarkdownLink(text, cursor);
+    if (!parsed) {
+      result += text[cursor++];
+      continue;
+    }
+
+    const style = parsed.image ? options.imageStyle : options.linkStyle;
+    if (style === 'wiki' && !parsed.target.includes('://')) {
+      const display = parsed.label;
+      const omitDisplay = parsed.image ? display === '' || display === parsed.target : display === parsed.target || display === defaultHeadingDisplay(parsed.target);
+      result += `${parsed.image ? '!' : ''}[[${parsed.target}${omitDisplay ? '' : `|${display}`}]]`;
+    } else {
+      result += text.substring(cursor, parsed.end);
+    }
+    cursor = parsed.end;
+  }
+
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = image ? start + 1 : start;
+  if (text[labelStart] !== '[' || (start > 0 && text[start - 1] === '\\\')) {
+    return null;
+  }
+
+  const labelEnd = findBalancedBracket(text, labelStart, '[', ']');
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const rawLabel = text.substring(labelStart + 1, labelEnd);
+  if (rawLabel.includes('\
') || rawLabel.includes('\\r')) {
+    return null;
+  }
+
+  const destination = parseDestination(text, labelEnd + 2);
+  if (!destination) {
+    return null;
+  }
+
+  return {end: destination.end, image, label: unescapeMarkdown(rawLabel), target: destination.target};
+}
+
+function findBalancedBracket(text: string, start: number, open: string, close: string): number {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === open) {
+      depth++;
+    } else if (text[index] === close && --depth === 0) {
+      return index;
+    } else if (text[index] === '\
' || text[index] === '\\r') {
+      return -1;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(text: string, start: number): {end: number, target: string} | null {
+  let index = start;
+  while (text[index] === ' ' || text[index] === '\	') index++;
+
+  if (text[index] === '<') {
+    const targetStart = ++index;
+    let rawTarget = '';
+    for (; index < text.length; index++) {
+      if (text[index] === '\\\') {
+        if (++index >= text.length) return null;
+        rawTarget += text[index];
+      } else if (text[index] === '>') {
+        break;
+      } else if (text[index] === '\
' || text[index] === '\\r') {
+        return null;
+      } else {
+        rawTarget += text[index];
+      }
+    }
+    if (index === text.length || index === targetStart) return null;
+    index++;
+    while (text[index] === ' ' || text[index] === '\	') index++;
+    return text[index] === ')' ? {end: index + 1, target: rawTarget} : null;
+  }
+
+  let depth = 0;
+  let rawTarget = '';
+  for (; index < text.length; index++) {
+    const character = text[index];
+    if (character === '\\\') {
+      if (++index >= text.length) return null;
+      rawTarget += text[index];
+    } else if (character === '(') {
+      depth++;
+      rawTarget += character;
+    } else if (character === ')') {
+      if (depth === 0) {
+        return rawTarget === '' ? null : {end: index + 1, target: rawTarget};
+      }
+      depth--;
+      rawTarget += character;
+    } else if (character === '\
' || character === '\\r' || character === ' ' || character === '\	') {
+      return null;
+    } else {
+      rawTarget += character;
+    }
+  }
+  return null;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingStart = target.indexOf('#');
+  if (headingStart === -1) return target;
+  const page = target.substring(0, headingStart);
+  const heading = target.substring(headingStart + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
+
+function isEmbedSize(display: string): boolean {
+  return /^\\d+(?:x\\d+)?$/.test(display);
+}
